package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;
import java.util.Random;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Teleporting strategy for the ball class
 */
public class TeleportingStrategy implements IUpdateStrategy {
	/**
	 * Every 20 ticks, the ball teleports to a random location on the screen
	 */
	private int ticks = 0;
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		ticks++;
		if (ticks > 20) {
			Random rand = new Random();
			int minX = ball.getRadius();
			int maxX = Math.max(minX, ball.getDimension().getWidth() - ball.getRadius());
			int minY = ball.getRadius();
			int maxY = Math.max(minY, ball.getDimension().getHeight() - ball.getRadius());
			int x = rand.nextInt(maxX - minX + 1) + minX;
			int y = rand.nextInt(maxY - minY + 1) + minY;
			ball.setLocation(new Point(x, y));
			ticks = 0;
		}
	}

}

package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;
import provided.utils.valueGenerator.impl.Randomizer;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * 
 * @author charlielockyer
 * A strategy in which a ball splits into two when it hits a wall
 */
public class ExplodingStrategy implements IUpdateStrategy{

	/**
	 * Track the first bounce seen on each axis so the strategy does not spawn
	 * continuously once a bounce flag has been set.
	 */
	private boolean seenXBounce = false;
	private boolean seenYBounce = false;

	/**
	 * Updates the state like in all strategies
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		boolean[] bounced = ball.hasBounced();
		boolean exploded = false;
		if (bounced[0] && !seenXBounce) {
			seenXBounce = true;
			exploded = true;
		}
		if (bounced[1] && !seenYBounce) {
			seenYBounce = true;
			exploded = true;
		}
		if (exploded) {
			Point location = new Point(ball.getLocation());
			Point velocity = new Point(-ball.getVelocity().x, -ball.getVelocity().y);
			Ball spawnedBall = new Ball(location, velocity, Randomizer.Singleton.randomColor(), ball.getRadius(),
					ball.getDimension(), new StraightStrategy());
			disp.addObserver(spawnedBall);
		}
	}

}

